using System.Text.RegularExpressions;

namespace GitHub.DistributedTask.Logging
{
    internal sealed class RegexSecret : ISecret
    {
        public RegexSecret(String pattern)
        {
            ArgumentUtility.CheckStringForNullOrEmpty(pattern, nameof(pattern));
            m_pattern = pattern;
            m_regex = new Regex(pattern);
        }

        public override Boolean Equals(Object obj)
        {
            var item = obj as RegexSecret;
            if (item == null)
            {
                return false;
            }
            return String.Equals(m_pattern, item.m_pattern, StringComparison.Ordinal);
        }

        public override int GetHashCode() => m_pattern.GetHashCode();

        public IEnumerable<ReplacementPosition> GetPositions(String input)
        {
            Int32 startIndex = 0;
            while (startIndex < input.Length)
            {
                var match = m_regex.Match(input, startIndex);
                if (match.Success)
                {
                    startIndex = match.Index + 1;
                    yield return new ReplacementPosition(match.Index, match.Length);
                }
                else
                {
                    yield break;
                }
            }
        }

        private readonly String m_pattern;
        private readonly Regex m_regex;
    }
}

using System;
using GitHub.DistributedTask.ObjectTemplating.Tokens;

namespace GitHub.DistributedTask.ObjectTemplating.Schema
{
    internal sealed class PropertyValue
    {
        internal PropertyValue(TemplateToken token)
        {
            if (token is StringToken stringToken)
            {
                Type = stringToken.Value;
            }
            else
            {
                var mapping = token.AssertMapping($"{TemplateConstants.MappingPropertyValue}");
                foreach (var mappingPair in mapping)
                {
                    var mappingKey = mappingPair.Key.AssertString($"{TemplateConstants.MappingPropertyValue} key");
                    switch (mappingKey.Value)
                    {
                        case TemplateConstants.Type:
                            Type = mappingPair.Value.AssertString($"{TemplateConstants.MappingPropertyValue} {TemplateConstants.Type}").Value;
                            break;
                        case TemplateConstants.Required:
                            Required = mappingPair.Value.AssertBoolean($"{TemplateConstants.MappingPropertyValue} {TemplateConstants.Required}").Value;
                            break;
                        default:
                            mappingKey.AssertUnexpectedValue($"{TemplateConstants.MappingPropertyValue} key");
                            break;
                    }
                }
            }
        }

        internal String Type { get; set; }

        internal Boolean Required { get; set; }
    }
}

using System;
using System.Collections.Generic;

namespace GitHub.DistributedTask.WebApi
{
    public static class SerializationHelper
    {
        public static void Copy<T>(
            ref List<T> source,
            ref List<T> target,
            Boolean clearSource = false)
        {
            if (source != null && source.Count > 0)
            {
                target = new List<T>(source);
            }

            if (clearSource)
            {
                source = null;
            }
        }

        public static void Copy<TKey, TValue>(
            ref IDictionary<TKey, TValue> source,
            ref IDictionary<TKey, TValue> target,
            Boolean clearSource = false)
        {
            Copy(ref source, ref target, EqualityComparer<TKey>.Default, clearSource);
        }

        public static void Copy<TKey, TValue>(
            ref IDictionary<TKey, TValue> source,
            ref IDictionary<TKey, TValue> target,
            IEqualityComparer<TKey> comparer,
            Boolean clearSource = false)
        {
            if (source != null && source.Count > 0)
            {
                target = new Dictionary<TKey, TValue>(source, comparer);
            }

            if (clearSource)
            {
                source = null;
            }
        }
    }
}

