internal sealed class ManualHealthCheck<T> : IManualHealthCheck<T>
{
    private static readonly object _lock = new();

    public HealthCheckResult Result
    {
        get
        {
            lock (_lock)
            {
                return field;
            }
        }
        set
        {
            lock (_lock)
            {
                field = value;
            }
        }
